3	function assertUniqueValues<T extends string>(values: readonly T[], label: string): readonly T[] {
4	  const seen = new Set<string>();
5	  const duplicates = new Set<string>();
6	  for (const value of values) {
7	    if (seen.has(value)) {
8	      duplicates.add(value);
9	      continue;
10	    }
11	    seen.add(value);
12	  }
13	  if (duplicates.size > 0) {
14	    throw new Error(`Duplicate ${label}: ${Array.from(duplicates).join(", ")}`);
15	  }
16	  return values;
17	}
