71	function chunkTextForOutbound(text: string, limit: number): string[] {
72	  const chunks: string[] = [];
73	  let remaining = text;
74	  while (remaining.length > limit) {
75	    const window = remaining.slice(0, limit);
76	    const splitAt = Math.max(window.lastIndexOf("\n"), window.lastIndexOf(" "));
77	    const breakAt = splitAt > 0 ? splitAt : limit;
78	    chunks.push(remaining.slice(0, breakAt).trimEnd());
79	    remaining = remaining.slice(breakAt).trimStart();
80	  }
81	  if (remaining.length > 0 || text.length === 0) {
82	    chunks.push(remaining);
83	  }
84	  return chunks;
85	}
