### 7. MESSAGE FLOW IMPLEMENTATION

**inbound.ts** (Message Reception):
```typescript
export async function handlePulseBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  statusSink?: (patch: { lastInboundAt?: number }) => void;
}): Promise<void> {
  const core = getPulseBoardRuntime();
  const pairing = createChannelPairingController({
    core,
    channel: "pulseboard",
    accountId: account.accountId,
  });

  // Parse message
  const rawBody = message.text?.trim() ?? "";
  if (!rawBody) return;

  // Check DM access policy
  const dmAccess = await resolvePulseBoardDirectAccess({
    cfg: config,
    accountId: account.accountId,
    dmPolicy: account.config.dmPolicy,
    allowFrom: account.config.allowFrom,
    senderPubkey: message.senderId,
    rawBody,
    runtime,
  });

  if (dmAccess.blocked) {
    logInboundDrop(...);
    return;
  }

  // Dispatch inbound to core
  await dispatchInboundDirectDmWithRuntime({
    ...dmAccess.access,
    channel: "pulseboard",
    accountId: account.accountId,
    senderId: message.senderId,
    conversationId: message.conversationId,
    messageId: message.messageId,
    body: rawBody,
    // ... other metadata
  });

  statusSink?.({ lastInboundAt: Date.now() });
}
```

**monitor.ts** (Message Polling):
```typescript
export async function monitorPulseBoardProvider(params: {
  runtime: RuntimeEnv;
}): Promise<void> {
  return runStoppablePassiveMonitor(async (monitor) => {
    while (!monitor.stopped) {
      try {
        // Poll for messages from all accounts
        for (const account of getActiveAccounts()) {
          const messages = await fetchMessages(account);
          for (const msg of messages) {
            await handlePulseBoardInbound({ message: msg, account, ... });
          }
        }

        // Sleep before next poll
        await monitor.sleep(pollingInterval);
      } catch (error) {
        // Handle errors
      }
    }
  });
}
```

**send.ts** (Message Sending):
```typescript
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const account = resolvePulseBoardAccount({ ... });

  if (!account.configured) {
    throw new Error(`PulseBoard not configured for account "${account.accountId}"`);
  }

  // Send via API
  const response = await sendViaApi(account, to, text);

  // Record outbound activity
  runtime.channel.activity.record({
    channel: "pulseboard",
    accountId: account.accountId,
    direction: "outbound",
  });

  return {
    messageId: response.id,
    target: to,
  };
}
```

