374	/**
375	 * Get public key from private key (hex or nsec format)
376	 */
377	export function getPublicKeyFromPrivate(privateKey: string): string {
378	  const sk = validatePrivateKey(privateKey);
379	  return getPublicKey(sk);
380	}
