763	/**
764	 * Send an encrypted DM to a pubkey
765	 */
766	async function sendEncryptedDm(
767	  pool: SimplePool,
768	  sk: Uint8Array,
769	  toPubkey: string,
770	  text: string,
771	  relays: string[],
772	  metrics: NostrMetrics,
773	  circuitBreakers: Map<string, CircuitBreaker>,
774	  healthTracker: RelayHealthTracker,
775	  onError?: (error: Error, context: string) => void,
776	): Promise<void> {
777	  const ciphertext = encrypt(sk, toPubkey, text);
778	  const reply = finalizeEvent(
779	    {
780	      kind: 4,
781	      content: ciphertext,
782	      tags: [["p", toPubkey]],
783	      created_at: Math.floor(Date.now() / 1000),
784	    },
785	    sk,
786	  );
787	
788	  // Sort relays by health score (best first)
789	  const sortedRelays = healthTracker.getSortedRelays(relays);
790	
791	  // Try relays in order of health, respecting circuit breakers
792	  let lastError: Error | undefined;
793	  for (const relay of sortedRelays) {
794	    const cb = circuitBreakers.get(relay);
795	
796	    // Skip if circuit breaker is open
797	    if (cb && !cb.canAttempt()) {
798	      continue;
799	    }
800	
801	    const startTime = Date.now();
802	    try {
803	      // oxlint-disable-next-line typescript/await-thenable typesciript/no-floating-promises
804	      await pool.publish([relay], reply);
805	      const latency = Date.now() - startTime;
806	
807	      // Record success
808	      cb?.recordSuccess();
809	      healthTracker.recordSuccess(relay, latency);
810	
811	      return; // Success - exit early
812	    } catch (err) {
813	      lastError = err as Error;
814	      const latency = Date.now() - startTime;
815	
816	      // Record failure
817	      cb?.recordFailure();
818	      healthTracker.recordFailure(relay);
819	      metrics.emit("relay.error", 1, { relay, latency });
820	
821	      onError?.(lastError, `publish to ${relay}`);
822	    }
823	  }
824	
825	  throw new Error(`Failed to publish to any relay: ${lastError?.message}`);
826	}
