119	/**
120	 * Create a signed kind:0 profile event.
121	 *
122	 * @param sk - Private key as Uint8Array (32 bytes)
123	 * @param profile - Profile data to include
124	 * @param lastPublishedAt - Previous profile timestamp (for monotonic guarantee)
125	 * @returns Signed Nostr event
126	 */
127	export function createProfileEvent(
128	  sk: Uint8Array,
129	  profile: NostrProfile,
130	  lastPublishedAt?: number,
131	): Event {
132	  const content = profileToContent(profile);
133	  const contentJson = JSON.stringify(content);
134	
135	  // Ensure monotonic timestamp (new event > previous)
136	  const now = Math.floor(Date.now() / 1000);
137	  const createdAt = lastPublishedAt !== undefined ? Math.max(now, lastPublishedAt + 1) : now;
138	
139	  const event = finalizeEvent(
140	    {
141	      kind: 0,
142	      content: contentJson,
143	      tags: [],
144	      created_at: createdAt,
145	    },
146	    sk,
147	  );
148	
149	  return event;
150	}

