1	export function isIrcControlChar(charCode: number): boolean {
2	  return charCode <= 0x1f || charCode === 0x7f;
3	}
4	
5	export function hasIrcControlChars(value: string): boolean {
6	  for (const char of value) {
7	    if (isIrcControlChar(char.charCodeAt(0))) {
8	      return true;
9	    }
10	  }
11	  return false;
12	}
