14	export function stripIrcControlChars(value: string): string {
15	  let out = "";
16	  for (const char of value) {
17	    if (!isIrcControlChar(char.charCodeAt(0))) {
18	      out += char;
19	    }
20	  }
21	  return out;
22	}
