205	/**
206	 * Create and publish a profile event in one call.
207	 *
208	 * @param pool - SimplePool instance
209	 * @param sk - Private key as Uint8Array
210	 * @param relays - Array of relay URLs
211	 * @param profile - Profile data
212	 * @param lastPublishedAt - Previous timestamp for monotonic ordering
213	 * @returns Publish results
214	 */
215	export async function publishProfile(
216	  pool: SimplePool,
217	  sk: Uint8Array,
218	  relays: string[],
219	  profile: NostrProfile,
220	  lastPublishedAt?: number,
221	): Promise<ProfilePublishResult> {
222	  const event = createProfileEvent(sk, profile, lastPublishedAt);
223	  return publishProfileEvent(pool, relays, event);
224	}
