230	/**
231	 * Validate a profile without throwing (returns result object).
232	 */
233	export function validateProfile(profile: unknown): {
234	  valid: boolean;
235	  profile?: NostrProfile;
236	  errors?: string[];
237	} {
238	  const result = NostrProfileSchema.safeParse(profile);
239	
240	  if (result.success) {
241	    return { valid: true, profile: result.data };
242	  }
243	
244	  return {
245	    valid: false,
246	    errors: result.error.issues.map((e) => `${e.path.join(".")}: ${e.message}`),
