250	/**
251	 * Sanitize profile text fields to prevent XSS when displaying in UI.
252	 * Escapes HTML special characters.
253	 */
254	export function sanitizeProfileForDisplay(profile: NostrProfile): NostrProfile {
255	  const escapeHtml = (str: string | undefined): string | undefined => {
256	    if (str === undefined) {
257	      return undefined;
258	    }
259	    return str
260	      .replace(/&/g, "&amp;")
261	      .replace(/</g, "&lt;")
262	      .replace(/>/g, "&gt;")
263	      .replace(/"/g, "&quot;")
264	      .replace(/'/g, "&#039;");
265	  };
266	
267	  return {
268	    name: escapeHtml(profile.name),
269	    displayName: escapeHtml(profile.displayName),
270	    about: escapeHtml(profile.about),
271	    picture: profile.picture, // URLs already validated by schema
272	    banner: profile.banner,
273	    website: profile.website,
274	    nip05: escapeHtml(profile.nip05),
275	    lud16: escapeHtml(profile.lud16),
276	  };
277	}
