160	async function readJsonBody(
161	  req: IncomingMessage,
162	  maxBytes = 64 * 1024,
163	  timeoutMs = 30_000,
164	): Promise<unknown> {
165	  const result = await readJsonBodyWithLimit(req, {
166	    maxBytes,
167	    timeoutMs,
168	    emptyObjectOnEmpty: true,
169	  });
170	  if (result.ok) {
171	    return result.value;
172	  }
173	  if (result.code === "PAYLOAD_TOO_LARGE") {
174	    throw new Error("Request body too large");
175	  }
176	  if (result.code === "REQUEST_BODY_TIMEOUT") {
177	    throw new Error(requestBodyErrorToText("REQUEST_BODY_TIMEOUT"));
178	  }
179	  if (result.code === "CONNECTION_CLOSED") {
180	    throw new Error(requestBodyErrorToText("CONNECTION_CLOSED"));
181	  }
182	  throw new Error(result.code === "INVALID_JSON" ? "Invalid JSON" : result.error);
183	}
