191	function isLoopbackRemoteAddress(remoteAddress: string | undefined): boolean {
192	  if (!remoteAddress) {
193	    return false;
194	  }
195	
196	  const ipLower = remoteAddress.toLowerCase().replace(/^\[|\]$/g, "");
197	
198	  // IPv6 loopback
199	  if (ipLower === "::1") {
200	    return true;
201	  }
202	
203	  // IPv4 loopback (127.0.0.0/8)
204	  if (ipLower === "127.0.0.1" || ipLower.startsWith("127.")) {
205	    return true;
206	  }
207	
208	  // IPv4-mapped IPv6
209	  const v4Mapped = ipLower.match(/^::ffff:(\d+\.\d+\.\d+\.\d+)$/);
210	  if (v4Mapped) {
211	    return isLoopbackRemoteAddress(v4Mapped[1]);
212	  }
213	
214	  return false;
215	}
216	
217	function isLoopbackOriginLike(value: string): boolean {
218	  try {
219	    const url = new URL(value);
220	    const hostname = url.hostname.toLowerCase();
221	    return hostname === "localhost" || hostname === "127.0.0.1" || hostname === "::1";
222	  } catch {
223	    return false;
224	  }
225	}
226	
227	function firstHeaderValue(value: string | string[] | undefined): string | undefined {
228	  if (Array.isArray(value)) {
229	    return value[0];
230	  }
231	  return typeof value === "string" ? value : undefined;
232	}
233	
234	function normalizeIpCandidate(raw: string): string {
235	  const unquoted = raw.trim().replace(/^"|"$/g, "");
236	  const bracketedWithOptionalPort = unquoted.match(/^\[([^[\]]+)\](?::\d+)?$/);
237	  if (bracketedWithOptionalPort) {
238	    return bracketedWithOptionalPort[1] ?? "";
239	  }
240	  const ipv4WithPort = unquoted.match(/^(\d+\.\d+\.\d+\.\d+):\d+$/);
241	  if (ipv4WithPort) {
242	    return ipv4WithPort[1] ?? "";
243	  }
244	  return unquoted;
245	}
246	
247	function hasNonLoopbackForwardedClient(req: IncomingMessage): boolean {
248	  const forwardedFor = firstHeaderValue(req.headers["x-forwarded-for"]);
249	  if (forwardedFor) {
250	    for (const hop of forwardedFor.split(",")) {
251	      const candidate = normalizeIpCandidate(hop);
252	      if (!candidate) {
253	        continue;
254	      }
255	      if (!isLoopbackRemoteAddress(candidate)) {
256	        return true;
257	      }
258	    }
259	  }
260	
261	  const realIp = firstHeaderValue(req.headers["x-real-ip"]);
262	  if (realIp) {
263	    const candidate = normalizeIpCandidate(realIp);
264	    if (candidate && !isLoopbackRemoteAddress(candidate)) {
265	      return true;
266	    }
267	  }
268	
269	  return false;
270	}
