272	function enforceLoopbackMutationGuards(
273	  ctx: NostrProfileHttpContext,
274	  req: IncomingMessage,
275	  res: ServerResponse,
276	): boolean {
277	  // Mutation endpoints are local-control-plane only.
278	  const remoteAddress = req.socket.remoteAddress;
279	  if (!isLoopbackRemoteAddress(remoteAddress)) {
280	    ctx.log?.warn?.(`Rejected mutation from non-loopback remoteAddress=${String(remoteAddress)}`);
281	    sendJson(res, 403, { ok: false, error: "Forbidden" });
282	    return false;
283	  }
284	
285	  // If a proxy exposes client-origin headers showing a non-loopback client,
286	  // treat this as a remote request and deny mutation.
287	  if (hasNonLoopbackForwardedClient(req)) {
288	    ctx.log?.warn?.("Rejected mutation with non-loopback forwarded client headers");
289	    sendJson(res, 403, { ok: false, error: "Forbidden" });
290	    return false;
291	  }
292	
293	  const secFetchSite = firstHeaderValue(req.headers["sec-fetch-site"])?.trim().toLowerCase();
294	  if (secFetchSite === "cross-site") {
295	    ctx.log?.warn?.("Rejected mutation with cross-site sec-fetch-site header");
296	    sendJson(res, 403, { ok: false, error: "Forbidden" });
297	    return false;
298	  }
299	
300	  // CSRF guard: browsers send Origin/Referer on cross-site requests.
301	  const origin = firstHeaderValue(req.headers.origin);
302	  if (typeof origin === "string" && !isLoopbackOriginLike(origin)) {
303	    ctx.log?.warn?.(`Rejected mutation with non-loopback origin=${origin}`);
304	    sendJson(res, 403, { ok: false, error: "Forbidden" });
305	    return false;
306	  }
307	
308	  const referer = firstHeaderValue(req.headers.referer ?? req.headers.referrer);
309	  if (typeof referer === "string" && !isLoopbackOriginLike(referer)) {
310	    ctx.log?.warn?.(`Rejected mutation with non-loopback referer=${referer}`);
311	    sendJson(res, 403, { ok: false, error: "Forbidden" });
312	    return false;
313	  }
314	
315	  return true;
316	}
