43	/** Downgrade sender-scoped group policy to open mode when no allowlist is configured. */
44	export function resolveSenderScopedGroupPolicy(params: {
45	  groupPolicy: GroupPolicy;
46	  groupAllowFrom: string[];
47	}): GroupPolicy {
48	  if (params.groupPolicy === "disabled") {
49	    return "disabled";
50	  }
51	  return params.groupAllowFrom.length > 0 ? "allowlist" : "open";
52	}
53	
54	/** Evaluate route-level group access after policy, route match, and enablement checks. */
55	export function evaluateGroupRouteAccessForPolicy(params: {
56	  groupPolicy: GroupPolicy;
57	  routeAllowlistConfigured: boolean;
58	  routeMatched: boolean;
59	  routeEnabled?: boolean;
60	}): GroupRouteAccessDecision {
61	  if (params.groupPolicy === "disabled") {
62	    return {
63	      allowed: false,
64	      groupPolicy: params.groupPolicy,
65	      reason: "disabled",
66	    };
67	  }
68	
69	  if (params.routeMatched && params.routeEnabled === false) {
70	    return {
71	      allowed: false,
72	      groupPolicy: params.groupPolicy,
73	      reason: "route_disabled",
74	    };
75	  }
76	
77	  if (params.groupPolicy === "allowlist") {
78	    if (!params.routeAllowlistConfigured) {
79	      return {
80	        allowed: false,
81	        groupPolicy: params.groupPolicy,
82	        reason: "empty_allowlist",
83	      };
84	    }
85	    if (!params.routeMatched) {
86	      return {
87	        allowed: false,
88	        groupPolicy: params.groupPolicy,
89	        reason: "route_not_allowlisted",
90	      };
91	    }
92	  }
93	
94	  return {
95	    allowed: true,
96	    groupPolicy: params.groupPolicy,
97	    reason: "allowed",
98	  };
99	}
100	
101	/** Evaluate generic allowlist match state for channels that compare derived group identifiers. */
102	export function evaluateMatchedGroupAccessForPolicy(params: {
103	  groupPolicy: GroupPolicy;
104	  allowlistConfigured: boolean;
105	  allowlistMatched: boolean;
106	  requireMatchInput?: boolean;
107	  hasMatchInput?: boolean;
108	}): MatchedGroupAccessDecision {
109	  if (params.groupPolicy === "disabled") {
110	    return {
111	      allowed: false,
112	      groupPolicy: params.groupPolicy,
113	      reason: "disabled",
114	    };
115	  }
116	
117	  if (params.groupPolicy === "allowlist") {
118	    if (params.requireMatchInput && !params.hasMatchInput) {
119	      return {
120	        allowed: false,
121	        groupPolicy: params.groupPolicy,
122	        reason: "missing_match_input",
123	      };
124	    }
125	    if (!params.allowlistConfigured) {
126	      return {
127	        allowed: false,
128	        groupPolicy: params.groupPolicy,
129	        reason: "empty_allowlist",
130	      };
131	    }
132	    if (!params.allowlistMatched) {
133	      return {
134	        allowed: false,
135	        groupPolicy: params.groupPolicy,
136	        reason: "not_allowlisted",
137	      };
138	    }
139	  }
140	
141	  return {
142	    allowed: true,
143	    groupPolicy: params.groupPolicy,
144	    reason: "allowed",
145	  };
146	}
147	
148	/** Evaluate sender access for an already-resolved group policy and allowlist. */
149	export function evaluateSenderGroupAccessForPolicy(params: {
150	  groupPolicy: GroupPolicy;
151	  providerMissingFallbackApplied?: boolean;
152	  groupAllowFrom: string[];
153	  senderId: string;
154	  isSenderAllowed: (senderId: string, allowFrom: string[]) => boolean;
155	}): SenderGroupAccessDecision {
156	  if (params.groupPolicy === "disabled") {
157	    return {
158	      allowed: false,
159	      groupPolicy: params.groupPolicy,
160	      providerMissingFallbackApplied: Boolean(params.providerMissingFallbackApplied),
161	      reason: "disabled",
162	    };
163	  }
164	  if (params.groupPolicy === "allowlist") {
165	    if (params.groupAllowFrom.length === 0) {
166	      return {
167	        allowed: false,
168	        groupPolicy: params.groupPolicy,
169	        providerMissingFallbackApplied: Boolean(params.providerMissingFallbackApplied),
170	        reason: "empty_allowlist",
171	      };
172	    }
173	    if (!params.isSenderAllowed(params.senderId, params.groupAllowFrom)) {
174	      return {
175	        allowed: false,
176	        groupPolicy: params.groupPolicy,
177	        providerMissingFallbackApplied: Boolean(params.providerMissingFallbackApplied),
178	        reason: "sender_not_allowlisted",
179	      };
180	    }
181	  }
182	
183	  return {
184	    allowed: true,
185	    groupPolicy: params.groupPolicy,
186	    providerMissingFallbackApplied: Boolean(params.providerMissingFallbackApplied),
187	    reason: "allowed",
188	  };
189	}
