191	/** Resolve provider fallback policy first, then evaluate sender access against that result. */
192	export function evaluateSenderGroupAccess(params: {
193	  providerConfigPresent: boolean;
194	  configuredGroupPolicy?: GroupPolicy;
195	  defaultGroupPolicy?: GroupPolicy;
196	  groupAllowFrom: string[];
197	  senderId: string;
198	  isSenderAllowed: (senderId: string, allowFrom: string[]) => boolean;
199	}): SenderGroupAccessDecision {
