/**
 * PulseBoard target normalization.
 *
 * Canonical forms:
 *   - Direct messages:  dm:<userId>
 *   - Board messages:   board:<boardName>
 *
 * Accepted input forms:
 *   - dm:<userId>          → dm:<userId>
 *   - @<userId>            → dm:<userId>
 *   - board:<boardName>    → board:<boardName>
 *   - #<boardName>         → board:<boardName>
 *   - pulseboard:<any above> → strip prefix then normalize
 */

const VALID_ID_RE = /^[a-zA-Z0-9_-]+$/;

/**
 * Normalize a raw target string to the canonical `dm:<id>` or `board:<name>` form.
 * Returns `undefined` if the input cannot be recognized as a valid target.
 */
export function normalizePulseBoardTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) return undefined;

  // Strip optional "pulseboard:" namespace prefix
  const stripped = trimmed.replace(/^pulseboard:/i, "");

  if (/^dm:/i.test(stripped)) {
    const id = stripped.slice(3).toLowerCase();
    return VALID_ID_RE.test(id) ? `dm:${id}` : undefined;
  }

  if (/^board:/i.test(stripped)) {
    const name = stripped.slice(6).toLowerCase();
    return VALID_ID_RE.test(name) ? `board:${name}` : undefined;
  }

  if (stripped.startsWith("@")) {
    const id = stripped.slice(1).toLowerCase();
    return VALID_ID_RE.test(id) ? `dm:${id}` : undefined;
  }

  if (stripped.startsWith("#")) {
    const name = stripped.slice(1).toLowerCase();
    return VALID_ID_RE.test(name) ? `board:${name}` : undefined;
  }

  return undefined;
}

/** Return true when the normalized target is a direct message. */
export function isPulseBoardDmTarget(target: string): boolean {
  return target.startsWith("dm:");
}

/** Return true when the normalized target is a board (group). */
export function isPulseBoardBoardTarget(target: string): boolean {
  return target.startsWith("board:");
}

/**
 * Strip the `dm:` or `board:` prefix and return just the id/name portion.
 * Assumes the target has already been normalized.
 */
export function extractPulseBoardTargetId(target: string): string {
  return target.replace(/^(?:dm:|board:)/, "");
}

/**
 * Return true when the raw string looks like a PulseBoard target identifier
 * (used as a hint in the target resolver).
 */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  return (
    /^pulseboard:/i.test(trimmed) ||
    /^dm:[a-zA-Z0-9_-]+$/.test(trimmed) ||
    /^board:[a-zA-Z0-9_-]+$/.test(trimmed) ||
    /^@[a-zA-Z0-9_-]+$/.test(trimmed) ||
    /^#[a-zA-Z0-9_-]+$/.test(trimmed)
  );
}

