import type { OpenClawConfig } from "../api.js";
import { resolvePulseBoardAccount } from "./types.js";

export interface PulseBoardProbeResult {
  ok: boolean;
  userId?: string;
  apiUrl?: string;
  latencyMs?: number;
  error?: string;
}

/**
 * Probe the PulseBoard API by calling GET /me.
 * Returns a structured result suitable for status reporting.
 */
export async function probePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
  timeoutMs?: number;
}): Promise<PulseBoardProbeResult> {
  const account = resolvePulseBoardAccount({ cfg: opts.cfg, accountId: opts.accountId });

  if (!account.configured) {
    return { ok: false, error: "Not configured: set channels.pulseboard.apiKey and userId" };
  }

  const start = Date.now();
  try {
    const response = await fetch(`${account.apiUrl}/me`, {
      headers: {
        Authorization: `Bearer ${account.apiKey}`,
        "X-PulseBoard-User": account.userId,
      },
      signal: AbortSignal.timeout(opts.timeoutMs ?? 10_000),
    });

    const latencyMs = Date.now() - start;

    if (!response.ok) {
      return {
        ok: false,
        error: `API returned HTTP ${response.status}`,
        apiUrl: account.apiUrl,
        latencyMs,
      };
    }

    return {
      ok: true,
      userId: account.userId,
      apiUrl: account.apiUrl,
      latencyMs,
    };
  } catch (err) {
    return {
      ok: false,
      error: err instanceof Error ? err.message : String(err),
      apiUrl: account.apiUrl,
      latencyMs: Date.now() - start,
    };
  }
}

