import { resolveMarkdownTableMode } from "openclaw/plugin-sdk/config-runtime";
import { convertMarkdownTables } from "openclaw/plugin-sdk/text-runtime";
import type { OpenClawConfig } from "../api.js";
import {
  extractPulseBoardTargetId,
  isPulseBoardBoardTarget,
  normalizePulseBoardTarget,
} from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { resolvePulseBoardAccount } from "./types.js";

export interface SendPulseBoardResult {
  messageId: string;
  target: string;
}

type SendPulseBoardOptions = {
  cfg?: OpenClawConfig;
  accountId?: string | null;
};

/**
 * Send a text message to a PulseBoard target (DM or board).
 *
 * @param to   Normalized target: `dm:<userId>` or `board:<boardName>`.
 * @param text Message text to send.
 * @param opts Optional config and account overrides.
 */
export async function sendPulseBoardMessage(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = opts.cfg ?? runtime.config.loadConfig();
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard not configured for account "${account.accountId}". ` +
        `Set channels.pulseboard.apiKey and channels.pulseboard.userId.`,
    );
  }
  if (!account.enabled) {
    throw new Error(`PulseBoard account "${account.accountId}" is disabled.`);
  }

  // Normalize the target in case raw forms like "@user" or "#board" are passed
  const normalizedTo = normalizePulseBoardTarget(to) ?? to;
  const targetId = extractPulseBoardTargetId(normalizedTo);

  // Convert markdown tables to plain text using the configured mode
  const tableMode = resolveMarkdownTableMode({
    cfg,
    channel: "pulseboard",
    accountId: account.accountId,
  });
  const prepared = convertMarkdownTables(text.trim(), tableMode);

  if (!prepared.trim()) {
    throw new Error("PulseBoard message must be non-empty.");
  }

  const endpoint = isPulseBoardBoardTarget(normalizedTo)
    ? `${account.apiUrl}/boards/${encodeURIComponent(targetId)}/messages`
    : `${account.apiUrl}/dms/${encodeURIComponent(targetId)}/messages`;

  const response = await fetch(endpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${account.apiKey}`,
      "X-PulseBoard-User": account.userId,
    },
    body: JSON.stringify({ text: prepared }),
    signal: AbortSignal.timeout(30_000),
  });

  if (!response.ok) {
    let body = "";
    try {
      body = await response.text();
    } catch {
      // Ignore read errors
    }
    throw new Error(`PulseBoard API error ${response.status}: ${body}`);
  }

  const data = (await response.json()) as { id?: string };
  const messageId = data.id ?? `pb-${Date.now()}`;

  runtime.channel.activity.record({
    channel: "pulseboard",
    accountId: account.accountId,
    direction: "outbound",
  });

  return { messageId, target: normalizedTo };
}

