import type { OpenClawConfig, PluginRuntime, RuntimeEnv } from "../api.js";
import {
  createChannelPairingController,
  dispatchInboundDirectDmWithRuntime,
  dispatchInboundReplyWithBase,
  logInboundDrop,
  resolveInboundDirectDmAccessWithRuntime,
} from "../runtime-api.js";
import {
  extractPulseBoardTargetId,
  isPulseBoardBoardTarget,
  isPulseBoardDmTarget,
} from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { sendPulseBoardMessage } from "./send.js";
import type { ResolvedPulseBoardAccount } from "./types.js";

const CHANNEL_ID = "pulseboard" as const;

export interface PulseBoardInboundMessage {
  messageId: string;
  /** Sender's PulseBoard user ID. */
  senderId: string;
  /** Normalized target: `dm:<userId>` or `board:<boardName>`. */
  target: string;
  text: string;
  /** Unix timestamp in milliseconds. */
  createdAt: number;
}

function isSenderAllowed(senderId: string, allowFrom: string[]): boolean {
  const normalized = senderId.trim().toLowerCase();
  for (const entry of allowFrom) {
    const e = String(entry).trim().toLowerCase();
    if (e === "*" || e === normalized) {
      return true;
    }
  }
  return false;
}

/**
 * Dispatch a single inbound PulseBoard message to the OpenClaw runtime.
 * Handles both direct messages (DMs) and board (group) messages.
 */
export async function handlePulseBoardInbound(opts: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  runtime: RuntimeEnv;
}): Promise<void> {
  const { message, account, runtime } = opts;
  const core: PluginRuntime = getPulseBoardRuntime();

  const rawBody = message.text.trim();
  if (!rawBody) return;

  // Skip messages the bot itself sent
  if (message.senderId === account.userId) return;

  const cfg: OpenClawConfig = core.config.loadConfig();

  if (isPulseBoardBoardTarget(message.target)) {
    await handleBoardInbound({ message, account, cfg, core, runtime, rawBody });
  } else if (isPulseBoardDmTarget(message.target)) {
    await handleDmInbound({ message, account, cfg, core, runtime, rawBody });
  }
  // Unknown target format — silently drop
}

// ---------------------------------------------------------------------------
// Board (group) inbound
// ---------------------------------------------------------------------------

async function handleBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  cfg: OpenClawConfig;
  core: PluginRuntime;
  runtime: RuntimeEnv;
  rawBody: string;
}): Promise<void> {
  const { message, account, cfg, core, runtime, rawBody } = params;

  const boardName = extractPulseBoardTargetId(message.target); // e.g. "announcements"
  const boardTarget = message.target; // "board:announcements"

  const route = core.channel.routing.resolveAgentRoute({
    cfg,
    channel: CHANNEL_ID,
    accountId: account.accountId,
    peer: { kind: "group", id: boardTarget },
  });

  const storePath = core.channel.session.resolveStorePath(cfg.session?.store, {
    agentId: route.agentId,
  });
  const envelopeOptions = core.channel.reply.resolveEnvelopeFormatOptions(cfg);
  const previousTimestamp = core.channel.session.readSessionUpdatedAt({
    storePath,
    sessionKey: route.sessionKey,
  });

  const body = core.channel.reply.formatAgentEnvelope({
    channel: "PulseBoard",
    from: boardName,
    timestamp: message.createdAt,
    previousTimestamp,
    envelope: envelopeOptions,
    body: rawBody,
  });

  const ctxPayload = core.channel.reply.finalizeInboundContext({
    Body: body,
    RawBody: rawBody,
    CommandBody: rawBody,
    From: `pulseboard:board:${boardName}`,
    To: `pulseboard:board:${boardName}`,
    SessionKey: route.sessionKey,
    AccountId: route.accountId ?? account.accountId,
    ChatType: "group",
    ConversationLabel: boardName,
    SenderName: message.senderId,
    SenderId: message.senderId,
    GroupSubject: boardName,
    Provider: CHANNEL_ID,
    Surface: CHANNEL_ID,
    MessageSid: message.messageId,
    Timestamp: message.createdAt,
    OriginatingChannel: CHANNEL_ID,
    OriginatingTo: `pulseboard:board:${boardName}`,
  });

  await dispatchInboundReplyWithBase({
    cfg,
    channel: CHANNEL_ID,
    accountId: account.accountId,
    route,
    storePath,
    ctxPayload,
    core,
    deliver: async (payload) => {
      const outboundText =
        payload && typeof payload === "object" && "text" in payload
          ? String((payload as { text?: string }).text ?? "")
          : "";
      if (!outboundText.trim()) return;
      const tableMode = core.channel.text.resolveMarkdownTableMode({
        cfg,
        channel: CHANNEL_ID,
        accountId: account.accountId,
      });
      const converted = core.channel.text.convertMarkdownTables(outboundText, tableMode);
      await sendPulseBoardMessage(boardTarget, converted, { accountId: account.accountId });
    },
    onRecordError: (err) => {
      runtime.error?.(
        `pulseboard: failed recording board session for ${boardName}: ${String(err)}`,
      );
    },
    onDispatchError: (err, info) => {
      runtime.error?.(`pulseboard: board ${info.kind} reply failed for ${boardName}: ${String(err)}`);
    },
  });
}

// ---------------------------------------------------------------------------
// DM (direct) inbound
// ---------------------------------------------------------------------------

async function handleDmInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  cfg: OpenClawConfig;
  core: PluginRuntime;
  runtime: RuntimeEnv;
  rawBody: string;
}): Promise<void> {
  const { message, account, cfg, core, runtime, rawBody } = params;

  const pairing = createChannelPairingController({
    core,
    channel: CHANNEL_ID,
    accountId: account.accountId,
  });

  const access = await resolveInboundDirectDmAccessWithRuntime({
    cfg,
    channel: CHANNEL_ID,
    accountId: account.accountId,
    dmPolicy: account.config.dmPolicy ?? "pairing",
    allowFrom: account.config.allowFrom,
    senderId: message.senderId,
    rawBody,
    isSenderAllowed,
    runtime: {
      shouldComputeCommandAuthorized: core.channel.commands.shouldComputeCommandAuthorized,
      resolveCommandAuthorizedFromAuthorizers:
        core.channel.commands.resolveCommandAuthorizedFromAuthorizers,
    },
    modeWhenAccessGroupsOff: "configured",
  });

  if (access.access.decision === "block") {
    logInboundDrop({
      log: (line) => runtime.log?.(line),
      channel: CHANNEL_ID,
      reason: access.access.reason,
      target: message.senderId,
    });
    return;
  }

  if (access.access.decision === "pairing") {
    await pairing.issueChallenge({
      senderId: message.senderId,
      senderIdLine: `Your PulseBoard user ID: ${message.senderId}`,
      sendPairingReply: async (text) => {
        await sendPulseBoardMessage(`dm:${message.senderId}`, text, {
          accountId: account.accountId,
        });
      },
      onCreated: () => {
        runtime.log?.(
          `pulseboard: pairing challenge issued to ${message.senderId}`,
        );
      },
      onReplyError: (err) => {
        runtime.error?.(
          `pulseboard: pairing reply failed for ${message.senderId}: ${String(err)}`,
        );
      },
    });
    return;
  }

  // decision === "allow"
  await dispatchInboundDirectDmWithRuntime({
    cfg,
    runtime: core,
    channel: CHANNEL_ID,
    channelLabel: "PulseBoard",
    accountId: account.accountId,
    peer: { kind: "direct", id: message.senderId },
    senderId: message.senderId,
    senderAddress: `pulseboard:dm:${message.senderId}`,
    recipientAddress: `pulseboard:dm:${account.userId}`,
    conversationLabel: message.senderId,
    rawBody,
    messageId: message.messageId,
    timestamp: message.createdAt,
    commandAuthorized: access.commandAuthorized,
    deliver: async (payload) => {
      const outboundText =
        payload && typeof payload === "object" && "text" in payload
          ? String((payload as { text?: string }).text ?? "")
          : "";
      if (!outboundText.trim()) return;
      const tableMode = core.channel.text.resolveMarkdownTableMode({
        cfg,
        channel: CHANNEL_ID,
        accountId: account.accountId,
      });
      const converted = core.channel.text.convertMarkdownTables(outboundText, tableMode);
      await sendPulseBoardMessage(`dm:${message.senderId}`, converted, {
        accountId: account.accountId,
      });
    },
