import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import type { OpenClawConfig, RuntimeEnv } from "../api.js";
import { handlePulseBoardInbound, type PulseBoardInboundMessage } from "./inbound.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { resolvePulseBoardAccount } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: OpenClawConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number }) => void;
};

/** Response shape expected from GET /messages */
interface PulseBoardMessagesResponse {
  messages?: PulseBoardInboundMessage[];
}

const POLL_INTERVAL_MS = 10_000;

/**
 * Start polling the PulseBoard API for new messages.
 *
 * Resolves immediately and runs the polling loop in the background.
 * Returns a `{ stop }` handle compatible with `runStoppablePassiveMonitor`.
 */
export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? core.config.loadConfig();
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}". ` +
        `Set channels.pulseboard.apiKey and channels.pulseboard.userId.`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  logger.info(
    `[${account.accountId}] starting PulseBoard monitor (userId: ${account.userId}, apiUrl: ${account.apiUrl})`,
  );

  let stopped = false;
  let sinceMs = Date.now();

  /** Fetch one batch of messages and dispatch each one. */
  const pollOnce = async (): Promise<void> => {
    if (stopped || opts.abortSignal?.aborted) return;

    const url = new URL(`${account.apiUrl}/messages`);
    url.searchParams.set("since", String(sinceMs));
    url.searchParams.set("limit", "50");

    const response = await fetch(url.toString(), {
      headers: {
        Authorization: `Bearer ${account.apiKey}`,
        "X-PulseBoard-User": account.userId,
      },
      signal: AbortSignal.timeout(30_000),
    });

    if (!response.ok) {
      logger.warn?.(`[${account.accountId}] poll failed: HTTP ${response.status}`);
      return;
    }

    const data = (await response.json()) as PulseBoardMessagesResponse;
    const messages = data.messages ?? [];

    for (const message of messages) {
      if (stopped || opts.abortSignal?.aborted) break;

      // Advance the cursor so we don't re-process this message
      if (message.createdAt >= sinceMs) {
        sinceMs = message.createdAt + 1;
      }

      core.channel.activity.record({
        channel: "pulseboard",
        accountId: account.accountId,
        direction: "inbound",
        at: message.createdAt,
      });

      await handlePulseBoardInbound({ message, account, runtime });
      opts.statusSink?.({ lastInboundAt: message.createdAt });
    }
  };

  /** Main polling loop — runs until stopped or aborted. */
  const loop = async (): Promise<void> => {
    while (!stopped && !opts.abortSignal?.aborted) {
      try {
        await pollOnce();
      } catch (err) {
        if (!stopped && !opts.abortSignal?.aborted) {
          logger.error?.(
            `[${account.accountId}] PulseBoard poll error: ${err instanceof Error ? err.message : String(err)}`,
          );
        }
      }

      if (stopped || opts.abortSignal?.aborted) break;

      // Sleep for POLL_INTERVAL_MS, but wake up early on abort
      await new Promise<void>((resolve) => {
        const timer = setTimeout(resolve, POLL_INTERVAL_MS);
        const onAbort = () => {
          clearTimeout(timer);
          resolve();
        };
        opts.abortSignal?.addEventListener("abort", onAbort, { once: true });
        if (stopped) {
          clearTimeout(timer);
          resolve();
        }
      });
    }

    logger.info(`[${account.accountId}] PulseBoard monitor stopped`);
  };

  // Start the loop in the background; runStoppablePassiveMonitor waits on abort
  void loop();

  return {
    stop: () => {
      stopped = true;
    },
  };
}

