import {
  DEFAULT_ACCOUNT_ID,
  normalizeAccountId,
  normalizeOptionalAccountId,
} from "openclaw/plugin-sdk/account-id";
import {
  listCombinedAccountIds,
  resolveListedDefaultAccountId,
} from "openclaw/plugin-sdk/account-resolution";
import { normalizeSecretInputString, type SecretInput } from "openclaw/plugin-sdk/secret-input";
import type { OpenClawConfig } from "../api.js";

export const PULSEBOARD_DEFAULT_API_URL = "https://api.pulseboard.example/v1";
export const PULSEBOARD_POLL_INTERVAL_MS = 10_000;

export interface PulseBoardAccountConfig {
  enabled?: boolean;
  name?: string;
  apiKey?: SecretInput;
  apiUrl?: string;
  userId?: string;
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
  boards?: string[];
}

export interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  /** True when both apiKey and userId are present. */
  configured: boolean;
  apiKey: string;
  apiUrl: string;
  userId: string;
  config: PulseBoardAccountConfig;
}

function getPulseBoardCfg(cfg: OpenClawConfig): PulseBoardAccountConfig | undefined {
  return (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;
}

function resolveConfiguredDefaultAccountId(cfg: OpenClawConfig): string | undefined {
  // Single-account model — no per-account defaultAccount field needed, but kept for consistency
  return normalizeOptionalAccountId(undefined);
}

/**
 * List all configured PulseBoard account IDs.
 * Returns [DEFAULT_ACCOUNT_ID] when an API key is present, otherwise empty.
 */
export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = getPulseBoardCfg(cfg);
  const apiKey =
    normalizeSecretInputString(pbCfg?.apiKey) ?? process.env["PULSEBOARD_API_KEY"] ?? "";
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: apiKey
      ? (resolveConfiguredDefaultAccountId(cfg) ?? DEFAULT_ACCOUNT_ID)
      : undefined,
  });
}

/**
 * Return the default PulseBoard account ID.
 */
export function resolveDefaultPulseBoardAccountId(cfg: OpenClawConfig): string {
  return resolveListedDefaultAccountId({
    accountIds: listPulseBoardAccountIds(cfg),
    configuredDefaultAccountId: resolveConfiguredDefaultAccountId(cfg),
  });
}

/**
 * Resolve a PulseBoard account from the config, merging env-var fallbacks.
 */
export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    opts.accountId ?? resolveDefaultPulseBoardAccountId(opts.cfg),
  );
  const pbCfg = getPulseBoardCfg(opts.cfg);

  const apiKey =
    normalizeSecretInputString(pbCfg?.apiKey) ?? process.env["PULSEBOARD_API_KEY"] ?? "";
  const userId = pbCfg?.userId ?? process.env["PULSEBOARD_USER_ID"] ?? "";
  const apiUrl = pbCfg?.apiUrl ?? process.env["PULSEBOARD_API_URL"] ?? PULSEBOARD_DEFAULT_API_URL;

  const configured = Boolean(apiKey && userId);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: pbCfg?.enabled !== false,
    configured,
    apiKey,
    apiUrl,
    userId,
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      apiKey: pbCfg?.apiKey,
      apiUrl: pbCfg?.apiUrl,
      userId: pbCfg?.userId,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
      boards: pbCfg?.boards,
    },
  };
}

import {
  AllowFromListSchema,
  buildChannelConfigSchema,
  DmPolicySchema,
} from "openclaw/plugin-sdk/channel-config-primitives";
import { buildSecretInputSchema } from "openclaw/plugin-sdk/secret-input";
import { z } from "openclaw/plugin-sdk/zod";

/**
 * Zod schema for channels.pulseboard.* configuration.
 */
export const PulseBoardConfigSchema = z.object({
  /** Optional display name for this account. */
  name: z.string().optional(),

  /** Whether this channel is enabled (defaults to true). */
  enabled: z.boolean().optional(),

  /** PulseBoard API bearer token. */
  apiKey: buildSecretInputSchema().optional(),

  /** PulseBoard API base URL (defaults to https://api.pulseboard.example/v1). */
  apiUrl: z.string().url().optional(),

  /** The bot's own user ID on PulseBoard. */
  userId: z.string().optional(),

  /** DM access policy: pairing, allowlist, open, or disabled. */
  dmPolicy: DmPolicySchema.optional(),

  /** Allowed sender IDs for DMs (userId strings). */
  allowFrom: AllowFromListSchema,

  /** Named boards to include in the directory. */
  boards: z.array(z.string()).optional(),
});

export type PulseBoardConfig = z.infer<typeof PulseBoardConfigSchema>;

/**
 * JSON Schema representation for the OpenClaw configuration UI.
 */
export const pulseBoardChannelConfigSchema = buildChannelConfigSchema(PulseBoardConfigSchema);

