import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
import type { OpenClawConfig } from "openclaw/plugin-sdk/config-runtime";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  hasConfiguredSecretInput,
  normalizeSecretInputString,
} from "openclaw/plugin-sdk/secret-input";
import {
  createTopLevelChannelParsedAllowFromPrompt,
  createTopLevelChannelDmPolicy,
  createStandardChannelSetupStatus,
  mergeAllowFromEntries,
  parseSetupEntriesWithParser,
  patchTopLevelChannelConfigSection,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import { formatDocsLink } from "openclaw/plugin-sdk/setup";
import { resolvePulseBoardAccount } from "./types.js";

const channel = "pulseboard" as const;

const PULSEBOARD_SETUP_HELP_LINES = [
  "Generate an API key from your PulseBoard account settings.",
  "Provide your PulseBoard user ID (the handle you log in with).",
  "Env vars supported: PULSEBOARD_API_KEY, PULSEBOARD_USER_ID, PULSEBOARD_API_URL.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const PULSEBOARD_ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard DMs by user ID.",
  "Examples:",
  "- alice",
  "- bob123",
  "- *  (allow all senders)",
  "Multiple entries: comma-separated.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

function parsePulseBoardAllowFrom(raw: string): { entries: string[]; error?: string } {
  return parseSetupEntriesWithParser(raw, (entry) => {
    const cleaned = entry.trim().toLowerCase();
    if (!cleaned) {
      return { error: `Empty entry` };
    }
    if (cleaned === "*") {
      return { value: "*" };
    }
    if (!/^[a-zA-Z0-9_-]+$/.test(cleaned)) {
      return { error: `Invalid PulseBoard user ID: "${entry}" (alphanumeric, _, - only)` };
    }
    return { value: cleaned };
  });
}

const promptPulseBoardAllowFrom = createTopLevelChannelParsedAllowFromPrompt({
  channel,
  defaultAccountId: DEFAULT_ACCOUNT_ID,
  noteTitle: "PulseBoard allowlist",
  noteLines: PULSEBOARD_ALLOW_FROM_HELP_LINES,
  message: "PulseBoard allowFrom",
  placeholder: "alice, bob123, *",
  parseEntries: parsePulseBoardAllowFrom,
  mergeEntries: ({ existing, parsed }) => mergeAllowFromEntries(existing, parsed),
});

const pulseBoardDmPolicy: ChannelSetupDmPolicy = createTopLevelChannelDmPolicy({
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) =>
    (cfg as OpenClawConfig).channels?.pulseboard?.dmPolicy ?? "pairing",
  promptAllowFrom: promptPulseBoardAllowFrom,
});

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: () => DEFAULT_ACCOUNT_ID,
  applyAccountName: ({ cfg, name }) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: name?.trim() ? { name: name.trim() } : {},
    }),
  validateInput: ({ input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      apiKey?: string;
      userId?: string;
      apiUrl?: string;
    };
    if (!typedInput.useEnv) {
      if (!typedInput.apiKey?.trim()) {
        return "PulseBoard requires --api-key or --use-env.";
      }
    }
    if (!typedInput.userId?.trim()) {
      return "PulseBoard requires a --user-id.";
    }
    if (typedInput.apiUrl?.trim()) {
      try {
        new URL(typedInput.apiUrl.trim());
      } catch {
        return "Invalid API URL — must be a valid https:// URL.";
      }
    }
    return null;
  },
  applyAccountConfig: ({ cfg, input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      apiKey?: string;
      userId?: string;
      apiUrl?: string;
    };
    return patchTopLevelChannelConfigSection({
      cfg,
      channel,
      enabled: true,
      clearFields: typedInput.useEnv ? ["apiKey"] : undefined,
      patch: {
        ...(typedInput.useEnv ? {} : { apiKey: typedInput.apiKey?.trim() }),
        ...(typedInput.userId?.trim() ? { userId: typedInput.userId.trim() } : {}),
        ...(typedInput.apiUrl?.trim() ? { apiUrl: typedInput.apiUrl.trim() } : {}),
      },
    });
  },
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
  resolveShouldPromptAccountIds: () => false,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API key and user ID",
    configuredHint: "configured",
    unconfiguredHint: "needs API key and user ID",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) => resolvePulseBoardAccount({ cfg }).configured,
    resolveExtraStatusLines: ({ cfg }) => {
      const account = resolvePulseBoardAccount({ cfg });
      const lines: string[] = [];
      if (account.userId) {
        lines.push(`User ID: ${account.userId}`);
      }
      if (account.apiUrl) {
        lines.push(`API URL: ${account.apiUrl}`);
      }
      return lines;
    },
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: PULSEBOARD_SETUP_HELP_LINES,
  },
  envShortcut: {
    prompt: "PULSEBOARD_API_KEY detected. Use env var?",
    preferredEnvVar: "PULSEBOARD_API_KEY",
    isAvailable: ({ cfg, accountId }) =>
      accountId === DEFAULT_ACCOUNT_ID &&
      Boolean(process.env.PULSEBOARD_API_KEY?.trim()) &&
      !hasConfiguredSecretInput(resolvePulseBoardAccount({ cfg, accountId }).config.apiKey),
    apply: async ({ cfg }) =>
      patchTopLevelChannelConfigSection({
        cfg,
        channel,
        enabled: true,
        clearFields: ["apiKey"],
        patch: {},
      }),
  },
  credentials: [
    {
      inputKey: "apiKey",
      providerHint: channel,
      credentialLabel: "API key",
      preferredEnvVar: "PULSEBOARD_API_KEY",
      helpTitle: "PulseBoard API key",
      helpLines: PULSEBOARD_SETUP_HELP_LINES,
      envPrompt: "PULSEBOARD_API_KEY detected. Use env var?",
      keepPrompt: "PulseBoard API key already configured. Keep it?",
      inputPrompt: "PulseBoard API key",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return {
          accountConfigured: account.configured,
          hasConfiguredValue: hasConfiguredSecretInput(account.config.apiKey),
          resolvedValue: normalizeSecretInputString(account.config.apiKey),
          envValue: process.env.PULSEBOARD_API_KEY?.trim(),
        };
      },
      applyUseEnv: async ({ cfg }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: ["apiKey"],
          patch: {},
        }),
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { apiKey: resolvedValue },
        }),
    },
  ],
  textInputs: [
    {
      inputKey: "userId",
      message: "PulseBoard user ID",
      placeholder: "youruserid",
      required: true,
      applyEmptyValue: false,
      helpTitle: "PulseBoard user ID",
      helpLines: [
        "Your PulseBoard login handle (alphanumeric, _, -).",
        "Env var: PULSEBOARD_USER_ID",
      ],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return account.userId ?? process.env.PULSEBOARD_USER_ID ?? "";
      },
      keepPrompt: (value) => `PulseBoard user ID set to "${value}". Keep it?`,
      validate: ({ value }) => {
        if (!value.trim()) return "User ID is required.";
        if (!/^[a-zA-Z0-9_-]+$/.test(value.trim())) {
          return "User ID must be alphanumeric (_, - allowed).";
        }
        return undefined;
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { userId: value.trim() },
        }),
    },
    {
      inputKey: "apiUrl",
      message: "PulseBoard API URL (optional, leave blank for default)",
      placeholder: "https://api.pulseboard.example/v1",
      required: false,
      applyEmptyValue: true,
      helpTitle: "PulseBoard API URL",
      helpLines: [
        "Override the default API base URL.",
        "Leave blank to use https://api.pulseboard.example/v1.",
        "Env var: PULSEBOARD_API_URL",
      ],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        // Only show a current value if it was explicitly configured (not default)
        const raw = account.config.apiUrl ?? "";
        return raw;
      },
      keepPrompt: (value) => `PulseBoard API URL set to "${value}". Keep it?`,
      validate: ({ value }) => {
        if (!value.trim()) return undefined;
        try {
          new URL(value.trim());
          return undefined;
        } catch {
          return "Invalid URL — must be a valid https:// URL.";
        }
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: value.trim() ? undefined : ["apiUrl"],
          patch: value.trim() ? { apiUrl: value.trim() } : {},
        }),
    },
  ],
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: { enabled: false },
    }),
};

