    };
    return patchTopLevelChannelConfigSection({
      cfg,
      channel,
      enabled: true,
      clearFields: typedInput.useEnv ? ["apiKey"] : undefined,
      patch: {
        ...(typedInput.useEnv ? {} : { apiKey: typedInput.apiKey?.trim() }),
        ...(typedInput.userId?.trim() ? { userId: typedInput.userId.trim() } : {}),
        ...(typedInput.apiUrl?.trim() ? { apiUrl: typedInput.apiUrl.trim() } : {}),
      },
    });
  },
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
  resolveShouldPromptAccountIds: () => false,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API key and user ID",
    configuredHint: "configured",
    unconfiguredHint: "needs API key and user ID",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) => resolvePulseBoardAccount({ cfg }).configured,
    resolveExtraStatusLines: ({ cfg }) => {
      const account = resolvePulseBoardAccount({ cfg });
      const lines: string[] = [];
      if (account.userId) {
        lines.push(`User ID: ${account.userId}`);
      }
      if (account.apiUrl) {
        lines.push(`API URL: ${account.apiUrl}`);
      }
      return lines;
    },
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: PULSEBOARD_SETUP_HELP_LINES,
  },
  envShortcut: {
    prompt: "PULSEBOARD_API_KEY detected. Use env var?",
    preferredEnvVar: "PULSEBOARD_API_KEY",
    isAvailable: ({ cfg, accountId }) =>
      accountId === DEFAULT_ACCOUNT_ID &&
      Boolean(process.env.PULSEBOARD_API_KEY?.trim()) &&
      !hasConfiguredSecretInput(resolvePulseBoardAccount({ cfg, accountId }).config.apiKey),
    apply: async ({ cfg }) =>
      patchTopLevelChannelConfigSection({
        cfg,
        channel,
        enabled: true,
        clearFields: ["apiKey"],
        patch: {},
      }),
  },
  credentials: [
    {
      inputKey: "apiKey",
      providerHint: channel,
      credentialLabel: "API key",
      preferredEnvVar: "PULSEBOARD_API_KEY",
      helpTitle: "PulseBoard API key",
      helpLines: PULSEBOARD_SETUP_HELP_LINES,
      envPrompt: "PULSEBOARD_API_KEY detected. Use env var?",
      keepPrompt: "PulseBoard API key already configured. Keep it?",
      inputPrompt: "PulseBoard API key",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return {
          accountConfigured: account.configured,
          hasConfiguredValue: hasConfiguredSecretInput(account.config.apiKey),
          resolvedValue: normalizeSecretInputString(account.config.apiKey),
          envValue: process.env.PULSEBOARD_API_KEY?.trim(),
        };
      },
      applyUseEnv: async ({ cfg }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: ["apiKey"],
          patch: {},
        }),
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { apiKey: resolvedValue },
        }),
    },
  ],
  textInputs: [
    {
      inputKey: "userId",
      message: "PulseBoard user ID",
      placeholder: "youruserid",
      required: true,
      applyEmptyValue: false,
      helpTitle: "PulseBoard user ID",
      helpLines: [
        "Your PulseBoard login handle (alphanumeric, _, -).",
        "Env var: PULSEBOARD_USER_ID",
      ],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return account.userId ?? process.env.PULSEBOARD_USER_ID ?? "";
      },
      keepPrompt: (value) => `PulseBoard user ID set to "${value}". Keep it?`,
      validate: ({ value }) => {
        if (!value.trim()) return "User ID is required.";
        if (!/^[a-zA-Z0-9_-]+$/.test(value.trim())) {
          return "User ID must be alphanumeric (_, - allowed).";
        }
        return undefined;
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { userId: value.trim() },
        }),
    },
    {
      inputKey: "apiUrl",
      message: "PulseBoard API URL (optional, leave blank for default)",
      placeholder: "https://api.pulseboard.example/v1",
      required: false,
      applyEmptyValue: true,
      helpTitle: "PulseBoard API URL",
      helpLines: [
        "Override the default API base URL.",
        "Leave blank to use https://api.pulseboard.example/v1.",
        "Env var: PULSEBOARD_API_URL",
      ],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        // Only show a current value if it was explicitly configured (not default)
        const raw = account.config.apiUrl ?? "";
        return raw;
      },
      keepPrompt: (value) => `PulseBoard API URL set to "${value}". Keep it?`,
      validate: ({ value }) => {
        if (!value.trim()) return undefined;
        try {
          new URL(value.trim());
          return undefined;
        } catch {
          return "Invalid URL — must be a valid https:// URL.";
        }
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: value.trim() ? undefined : ["apiUrl"],
          patch: value.trim() ? { apiUrl: value.trim() } : {},
        }),
    },
  ],
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: { enabled: false },
    }),
};

