  type ResolvedPulseBoardAccount,
} from "./types.js";

const pulseBoardConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedPulseBoardAccount>({
  sectionKey: "pulseboard",
  resolveAccount: (cfg) => resolvePulseBoardAccount({ cfg }),
  listAccountIds: listPulseBoardAccountIds,
  defaultAccountId: resolveDefaultPulseBoardAccountId,
  deleteMode: "clear-fields",
  clearBaseFields: ["name", "apiKey", "apiUrl", "userId", "dmPolicy", "allowFrom", "boards"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom
      .map((entry) => String(entry).trim().toLowerCase())
      .filter(Boolean),
});

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  normalizeEntry: (e) => e.trim().toLowerCase(),
});

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (API Key)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin boards; post to boards or send direct messages.",
      markdownCapable: true,
      quickstartAllowFrom: true,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: pulseBoardChannelConfigSchema,
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {
            userId: account.userId,
            apiUrl: account.apiUrl,
          },
        }),
    },
    directory: createChannelDirectoryAdapter({
      listGroups: async ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return (account.config.boards ?? []).map((b) => ({
          kind: "group" as const,
          id: `board:${b}`,
          name: b,
        }));
      },
    }),
    status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
      defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
      collectStatusIssues: (accounts) =>
        collectStatusIssuesFromLastError("pulseboard", accounts),
      buildChannelSummary: ({ snapshot }) =>
        buildPassiveChannelStatusSummary(snapshot, {
          userId: (snapshot as Record<string, unknown>).userId ?? null,
          apiUrl: (snapshot as Record<string, unknown>).apiUrl ?? null,
        }),
      resolveAccountSnapshot: ({ account, runtime }) => ({
        accountId: account.accountId,
        name: account.name,
        enabled: account.enabled,
        configured: account.configured,
        extra: {
          userId: account.userId,
          apiUrl: account.apiUrl,
          ...buildTrafficStatusSummary(runtime),
        },
      }),
    }),
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;

        if (!account.configured) {
          throw new Error(
            `PulseBoard is not configured for account "${account.accountId}". ` +
              `Set channels.pulseboard.apiKey and channels.pulseboard.userId.`,
          );
        }

        ctx.log?.info(
          `[${account.accountId}] starting PulseBoard provider (userId: ${account.userId}, apiUrl: ${account.apiUrl})`,
        );

        await runStoppablePassiveMonitor({
          abortSignal: ctx.abortSignal,
          start: async () =>
            await monitorPulseBoardProvider({
              accountId: account.accountId,
              config: ctx.cfg,
              runtime: ctx.runtime,
              abortSignal: ctx.abortSignal,
              statusSink: (patch) => {
                if (patch.lastInboundAt !== undefined) {
                  ctx.setStatus?.({ lastInboundAt: patch.lastInboundAt });
                }
              },
            }),
        });
      },
    },
    messaging: {
      normalizeTarget: normalizePulseBoardTarget,
      targetResolver: {
        looksLikeId: looksLikePulseBoardTargetId,
        hint: "<dm:<userId>|board:<boardName>|@user|#board>",
      },
    },
  },
  pairing: {
    text: {
      idLabel: "pulseBoardUserId",
      message: "Your pairing request has been approved!",
      normalizeAllowEntry: (e) => e.trim().toLowerCase(),
      notify: async ({ id, message }) => {
        await sendPulseBoardMessage(`dm:${id}`, message, {
          accountId: DEFAULT_ACCOUNT_ID,
        });
      },
    },
  },
  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      const result = await sendPulseBoardMessage(to, text ?? "", { cfg, accountId });
      return attachChannelToResult("pulseboard", result);
    },
    sendMedia: async ({ cfg, to, text, mediaUrl, accountId }) => {
      const fullText = mediaUrl
        ? `${text ?? ""}\n\nAttachment: ${mediaUrl}`.trim()
        : (text ?? "");
      const result = await sendPulseBoardMessage(to, fullText, { cfg, accountId });
      return attachChannelToResult("pulseboard", result);
    },
  },
});

